(window.webpackJsonp=window.webpackJsonp||[]).push([[75],{547:function(t,e,n){"use strict";n.r(e);var r=n(0),o=Object(r.a)({},(function(){return this._self._c("ContentSlotsDistributor",{attrs:{"slot-key":this.$parent.slotKey}},[this._self._c("div",{domProps:{innerHTML:"<p>&lt;div class=&quot;custom-block tip&quot;&gt;&lt;p class=&quot;custom-block-title&quot;&gt;摘要&lt;/p&gt;\n将 Three.js 集成到 Vue 3 项目中并非简单的引入，涉及到生命周期管理、响应式数据与 3D 场景的桥接、组件化封装、内存泄漏防护等诸多工程问题。本文基于数字孪生机房项目的实践经验，分享 Vue 3 + Three.js 工程化集成的最佳方案。\n&lt;/div&gt;</p>\n<h2>一、核心挑战</h2>\n<p>Vue 3 和 Three.js 分属不同的渲染体系：</p>\n<table>\n<thead>\n<tr>\n<th>维度</th>\n<th>Vue 3</th>\n<th>Three.js</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td>渲染目标</td>\n<td>DOM</td>\n<td>WebGL Canvas</td>\n</tr>\n<tr>\n<td>数据驱动</td>\n<td>响应式 Proxy</td>\n<td>手动更新</td>\n</tr>\n<tr>\n<td>更新频率</td>\n<td>事件触发</td>\n<td>每帧 60fps</td>\n</tr>\n<tr>\n<td>内存管理</td>\n<td>GC 自动回收</td>\n<td>需手动 dispose</td>\n</tr>\n</tbody>\n</table>\n<p>直接混合使用会导致性能问题和内存泄漏，需要建立清晰的边界。</p>\n<h2>二、组合式 API 封装</h2>\n<h3>useThreeScene 核心 Hook</h3>\n<pre><code class=\"language-javascript\">import { onMounted, onBeforeUnmount, ref, shallowRef } from 'vue'\nimport * as THREE from 'three'\nimport { OrbitControls } from 'three/examples/jsm/controls/OrbitControls'\n\nexport function useThreeScene(containerRef) {\n  // 使用 shallowRef 避免 Vue 深度代理 Three.js 对象\n  const scene = shallowRef(null)\n  const camera = shallowRef(null)\n  const renderer = shallowRef(null)\n  const controls = shallowRef(null)\n  const isReady = ref(false)\n\n  let animationId = null\n\n  function init() {\n    const container = containerRef.value\n    if (!container) return\n\n    // Scene\n    scene.value = new THREE.Scene()\n    scene.value.background = new THREE.Color(0x1a1a2e)\n\n    // Camera\n    const aspect = container.clientWidth / container.clientHeight\n    camera.value = new THREE.PerspectiveCamera(45, aspect, 0.1, 1000)\n    camera.value.position.set(20, 15, 20)\n\n    // Renderer\n    renderer.value = new THREE.WebGLRenderer({\n      antialias: true,\n      alpha: true\n    })\n    renderer.value.setSize(container.clientWidth, container.clientHeight)\n    renderer.value.setPixelRatio(Math.min(window.devicePixelRatio, 2))\n    container.appendChild(renderer.value.domElement)\n\n    // Controls\n    controls.value = new OrbitControls(camera.value, renderer.value.domElement)\n    controls.value.enableDamping = true\n\n    isReady.value = true\n  }\n\n  function animate() {\n    animationId = requestAnimationFrame(animate)\n    controls.value?.update()\n    if (renderer.value &amp;&amp; scene.value &amp;&amp; camera.value) {\n      renderer.value.render(scene.value, camera.value)\n    }\n  }\n\n  function handleResize() {\n    const container = containerRef.value\n    if (!container || !camera.value || !renderer.value) return\n    camera.value.aspect = container.clientWidth / container.clientHeight\n    camera.value.updateProjectionMatrix()\n    renderer.value.setSize(container.clientWidth, container.clientHeight)\n  }\n\n  onMounted(() =&gt; {\n    init()\n    animate()\n    window.addEventListener('resize', handleResize)\n  })\n\n  onBeforeUnmount(() =&gt; {\n    window.removeEventListener('resize', handleResize)\n    if (animationId) cancelAnimationFrame(animationId)\n\n    // 彻底清理\n    scene.value?.traverse((child) =&gt; {\n      if (child.isMesh) {\n        child.geometry?.dispose()\n        if (Array.isArray(child.material)) {\n          child.material.forEach(m =&gt; m.dispose())\n        } else {\n          child.material?.dispose()\n        }\n      }\n    })\n    renderer.value?.dispose()\n    renderer.value?.forceContextLoss()\n    controls.value?.dispose()\n  })\n\n  return { scene, camera, renderer, controls, isReady }\n}\n</code></pre>\n<h2>三、关键原则：shallowRef</h2>\n<p><strong>绝对不要</strong>用 <code>ref</code> 或 <code>reactive</code> 包裹 Three.js 对象。Vue 3 的 Proxy 会深度代理对象的所有属性，Three.js 的 <code>Vector3</code>、<code>Matrix4</code> 等对象有大量内部属性，被代理后会严重影响性能。</p>\n<pre><code class=\"language-javascript\">// ❌ 错误：会触发深度代理\nconst mesh = ref(new THREE.Mesh(geometry, material))\n\n// ✅ 正确：只代理引用本身\nconst mesh = shallowRef(new THREE.Mesh(geometry, material))\n\n// ✅ 正确：不需要响应式的对象用普通变量\nlet mesh = new THREE.Mesh(geometry, material)\n</code></pre>\n<h2>四、数据桥接层</h2>\n<p>Vue 的响应式数据和 Three.js 场景之间需要一个桥接层：</p>\n<pre><code class=\"language-javascript\">export function useDeviceSync(scene, devices) {\n  const deviceMeshMap = new Map()\n\n  // 监听设备数据变化，同步到 3D 场景\n  watch(devices, (newDevices) =&gt; {\n    newDevices.forEach((device) =&gt; {\n      const mesh = deviceMeshMap.get(device.id)\n      if (!mesh) return\n\n      // 根据设备状态更新颜色\n      const statusColors = {\n        normal: 0x52c41a,\n        warning: 0xfaad14,\n        error: 0xff4d4f,\n        offline: 0x999999\n      }\n      mesh.material.color.setHex(statusColors[device.status] || 0xcccccc)\n      mesh.material.needsUpdate = true\n\n      // 更新标签内容\n      updateLabel(device.id, device)\n    })\n  }, { deep: true })\n\n  function registerDevice(id, mesh) {\n    deviceMeshMap.set(id, mesh)\n  }\n\n  function unregisterDevice(id) {\n    deviceMeshMap.delete(id)\n  }\n\n  return { registerDevice, unregisterDevice }\n}\n</code></pre>\n<h2>五、组件结构</h2>\n<pre><code>src/\n  components/\n    ThreeScene/\n      index.vue           # 3D 容器组件\n      hooks/\n        useThreeScene.js   # 场景初始化\n        useModelLoader.js  # 模型加载\n        useRaycaster.js    # 射线检测\n        useRoaming.js      # 漫游控制\n      modules/\n        SceneManager.js    # 场景管理类\n        LabelManager.js    # 标签管理类\n        DeviceManager.js   # 设备管理类\n      shaders/             # 自定义着色器\n      utils/               # 工具函数\n</code></pre>\n<h2>六、性能监控集成</h2>\n<pre><code class=\"language-javascript\">export function usePerformanceMonitor(renderer) {\n  const fps = ref(0)\n  const drawCalls = ref(0)\n  const triangles = ref(0)\n\n  let frameCount = 0\n  let lastTime = performance.now()\n\n  function update() {\n    frameCount++\n    const now = performance.now()\n    if (now - lastTime &gt;= 1000) {\n      fps.value = frameCount\n      frameCount = 0\n      lastTime = now\n\n      const info = renderer.value?.info\n      if (info) {\n        drawCalls.value = info.render.calls\n        triangles.value = info.render.triangles\n      }\n    }\n  }\n\n  return { fps, drawCalls, triangles, update }\n}\n</code></pre>\n<h2>七、总结</h2>\n<p>Vue 3 + Three.js 工程化集成的关键要点：</p>\n<ol>\n<li><strong>使用 shallowRef</strong>：避免 Vue Proxy 代理 Three.js 对象</li>\n<li><strong>生命周期管理</strong>：onBeforeUnmount 中彻底释放资源</li>\n<li><strong>数据桥接</strong>：通过 watch 单向同步数据到 3D 场景</li>\n<li><strong>模块化</strong>：将 3D 逻辑封装为独立的 hooks 和 class</li>\n<li><strong>性能隔离</strong>：3D 渲染循环独立于 Vue 更新周期</li>\n</ol>\n"}})])}),[],!1,null,null,null);e.default=o.exports}}]);